import { useState } from "react"

export default function ResumeScreener() {
  const [resumes, setResumes] = useState([])
  const [results, setResults] = useState([])
  const [loading, setLoading] = useState(false)

  const handleUpload = async (files) => {
    setLoading(true)
    const formData = new FormData()
    files.forEach(f => formData.append("resumes", f))

    const response = await fetch("/api/screen", {
      method: "POST",
      body: formData,
    })
    const data = await response.json()
    setResults(data.rankings)
    setLoading(false)
  }

  return (
    <div className="max-w-4xl mx-auto p-8">
      <h1 className="text-3xl font-bold">AI Resume Screener</h1>
      <p className="text-gray-600 mt-2">Upload resumes to automatically rank candidates</p>

      <input
        type="file"
        multiple
        accept=".pdf,.docx"
        onChange={(e) => handleUpload(Array.from(e.target.files))}
        className="mt-6"
      />

      {loading && <p className="mt-4">Screening resumes...</p>}

      {results.length > 0 && (
        <div className="mt-8">
          <h2 className="text-xl font-semibold">Rankings</h2>
          {results.map((r, i) => (
            <div key={i} className="border p-4 mt-2 rounded">
              <span className="font-bold">#{i + 1}</span> {r.name} —
              <span className="text-green-600"> Score: {r.score}/100</span>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

